// // This module implements an 8-bit synchronous Johnson counter with a synchronous reset. The counter shifts its bits to the right and inserts the inverted bit of the least significant bit at the most significant bit. Reset the counter to zero if the reset signal (rst) is low.
module sync_johnson_counter(
    input clk,
    input rst,
    output reg [7:0] q
    );

    always @(posedge clk) begin
        if (rst) begin
            q <= 8'b0;
        end else begin
            q <= {q[6:0], ~q[7]};
        end
    end
endmodule
